/**
 * FileTreeComponent - 文件树组件
 */
import { ApiClient } from '../infrastructure/ApiClient.js';
import { EventBus } from '../infrastructure/EventBus.js';

export const FileTreeComponent = {
    name: 'FileTreeComponent',
    props: {
        workspaceId: { type: String, default: null }
    },
    template: `
        <div class="file-tree">
            <div class="tree-header">
                <span class="tree-title">📂 工作区文件</span>
                <button class="btn btn-sm" @click="refresh">🔄</button>
            </div>
            <div class="tree-content">
                <div v-if="!workspaceId" class="empty-state">
                    请先选择项目和工作区
                </div>
                <div v-else-if="loading" class="loading">加载中...</div>
                <div v-else class="tree-nodes">
                    <div v-for="node in treeData" :key="node.path" class="tree-node" @click="handleNodeClick(node)">
                        <span class="node-icon">{{ node.type === 'directory' ? '📁' : '📄' }}</span>
                        <span class="node-name">{{ node.name }}</span>
                    </div>
                </div>
            </div>
        </div>
    `,
    data() {
        return {
            treeData: [],
            loading: false
        };
    },
    watch: {
        workspaceId() {
            this.loadTree();
        }
    },
    methods: {
        async loadTree() {
            if (!this.workspaceId) return;
            this.loading = true;
            try {
                const result = await ApiClient.get(`/workspaces/${this.workspaceId}/tree`);
                this.treeData = result.data || result || [];
            } catch (error) {
                console.error('Load tree error:', error);
            } finally {
                this.loading = false;
            }
        },
        handleNodeClick(node) {
            if (node.type === 'file') {
                EventBus.emit('file:selected', { file: node });
            }
        },
        refresh() {
            this.loadTree();
        }
    }
};

window.FileTreeComponent = FileTreeComponent;
